    44→    public static object ResolveUnRegistered(Type type)
    45→    {
    46→      var constructors = type.GetConstructors();
    47→      foreach (var constructor in constructors)
    48→      {
    49→        try
    50→        {
    51→          var parameters = constructor.GetParameters();
    52→          var parameterInstances = new List<object>();
    53→          foreach (var parameter in parameters)
    54→          {
    55→            var service = Resolve(parameter.ParameterType);
    56→            if (service == null) throw new Exception("Unknown dependency");
    57→            parameterInstances.Add(service);
    58→          }
    59→          return Activator.CreateInstance(type, parameterInstances.ToArray());
